import React from 'react';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import { Link } from 'react-router-dom';

const DrawerMenu = ({ categories }) => {
  const generateMenuItems = () => {
    if (!Array.isArray(categories) || categories.length === 0) {
      return null;
    }

    return categories.map((category) => {
      const { _id, mainMenu, subMenu } = category;

      if (!_id || !mainMenu) {
        return null; // Skip invalid category
      }

      return (
        <List key={_id} component="nav">
          <ListItem button component={Link} to={`/${mainMenu}`}>
            <ListItemText primary={mainMenu} />
          </ListItem>
          {Array.isArray(subMenu) && subMenu.length > 0 && (
            <List component="div" disablePadding>
              {subMenu.map((subItem) => {
                if (!subItem || !subItem._id) {
                  return null; // Skip invalid subItem
                }

                return (
                  <ListItem
                    key={subItem._id}
                    button
                    component={Link}
                    to={`/${mainMenu}/${subItem}`}
                    style={{ paddingLeft: 16 }}
                  >
                    <ListItemText primary={subItem} />
                  </ListItem>
                );
              })}
            </List>
          )}
        </List>
      );
    });
  };

  return <div>{generateMenuItems()}</div>;
};

export default DrawerMenu;
